		"FSC360NEW/fragment/CreateTemplate_dash.fragment.xml": "<core:FragmentDefinition xmlns=\"sap.m\" xmlns:core=\"sap.ui.core\">\r\n  <Popover\r\n    title=\"Create New Template\"\r\n    placement=\"Bottom\"\r\n    class=\"sapUiContentPadding clcustomizecreatetemppop\"\r\n    id=\"idCreateTemplatePopover\">\r\n\r\n    <!-- Main Content -->\r\n    <VBox class=\"customcol_padding\">\r\n      <Label text=\"Template Name\" class=\"popup_subheading\" />\r\n      <Input id=\"idNewTemplateName\" placeholder=\"Enter Name\" class=\"templateSelectWrapper\" />\r\n\r\n      <List id=\"idNewFieldList\" items=\"{FilterTableModel>/}\" class=\"noListBorder\">\r\n        <CustomListItem>\r\n          <HBox alignItems=\"Center\" class=\"clListItemStyled customCheckWrapper\">\r\n            <Image src=\"Images/dots-drag.svg\" class=\"dots-drag\"/>\r\n            <CheckBox selected=\"{FilterTableModel>visible}\" width=\"100%\"/>\r\n            <Text text=\"{FilterTableModel>label}\" class=\"sapUiTinyMarginEnd popuptext\"/>\r\n          </HBox>\r\n        </CustomListItem>\r\n      </List>\r\n    </VBox>\r\n\r\n    <!-- Footer Section -->\r\n    <footer>\r\n      <Bar design=\"Footer\" class=\"grey_background\">\r\n        <contentRight>\r\n          <Button text=\"{i18n>Cancel}\" \r\n                  type=\"Transparent\" \r\n                  class=\"whitebtn bluebtnfragment\"\r\n                  press=\"fn_onCancelCreateTemplate\"/>\r\n          <Button text=\"Save\" \r\n                  type=\"Emphasized\" \r\n                  class=\"bluebtn bluebtnfragment bluebtngap\"\r\n                  press=\"fn_onSaveNewTemplate\"/>\r\n        </contentRight>\r\n      </Bar>\r\n    </footer>\r\n    \r\n  </Popover>\r\n</core:FragmentDefinition>",
		"FSC360NEW/fragment/upload.fragment.xml": "<core:FragmentDefinition xmlns=\"sap.m\" xmlns:u=\"sap.ui.unified\" xmlns:ui=\"sap.ui.table\" xmlns:core=\"sap.ui.core\" xmlns:l=\"sap.ui.layout\"\r\n  xmlns:f=\"sap.ui.layout.form\">\r\n  <Dialog title=\"Upload GL details\"  class=\"cl_agentDialog\">\r\n\t<VBox alignContent=\"Center\" justifyContent=\"Center\" alignItems=\"Center\">\r\n    <u:FileUploader typeMissmatch=\"handleTypeMissmatch\" fileType=\"xlsx,csv,xls\" change=\"handleUploadComplete\" id=\"fileuploaderPO\" style=\"Emphasized\"\r\n                    icon=\"sap-icon://upload\" class=\"cl_MassUpload sapUiTinyMargin sapUiSizeCompact\" uploadComplete=\"handleUploadComplete\"  placeholder=\"Choose a file for Upload...\"></u:FileUploader>\r\n\t</VBox>\r\n    <beginButton>\r\n      <Button type=\"Emphasized\" class=\"sapUiSizeCompact gl_subbtn simpost \" icon=\"Images/sub.svg\" press=\"fn_uploadSubmit\"  text=\"{i18n>Submit}\"/>\r\n    </beginButton>\r\n    <endButton>\r\n      <Button type=\"Emphasized\"  icon=\"Images/cancel.svg\" class=\"sapUiSizeCompact sapUiSmallMarginEnd gl_canbtn simcan\" text=\"{i18n>Cancel}\" press=\"fn_uploadCancel\"/>\r\n    </endButton>\r\n  </Dialog>\r\n</core:FragmentDefinition>",
