		"FSC360NEW/fragment/Summary.fragment.xml": "<core:FragmentDefinition xmlns=\"sap.m\" xmlns:core=\"sap.ui.core\" xmlns:u=\"sap.ui.unified\" xmlns:l=\"sap.ui.layout\"\r\n  xmlns:f=\"sap.ui.layout.form\" xmlns:uitable=\"sap.ui.table\">\r\n  <Dialog title=\"Summary\" contentHeight=\"100%\" contentWidth=\"40%\" showHeader=\"true\" class=\"cl_agentDialog cl_frag_rightslidesum\">\r\n   <content>\r\n   \t<VBox class=\"summary\">\r\n   \t<uitable:Table id=\"id_Sel_Table\"\r\n    rows=\"{LNSumm>/}\"\r\n    visibleRowCount=\"5\"\r\n    selectionMode=\"None\"\r\n    class=\"MTableClass simtable\"\r\n    noDataText=\"Loading...\">\r\n\r\n    <!-- Column: Condition -->\r\n    <uitable:Column>\r\n        <Label text=\"Condition\" class=\"TableTextClass\"/>\r\n        <uitable:template>\r\n            <Text text=\"{LNSumm>Kschl}-{LNSumm>Vtext}\"/>\r\n        </uitable:template>\r\n    </uitable:Column>\r\n\r\n    <!-- Column: Liability -->\r\n    <uitable:Column>\r\n        <Label text=\"Liability\" class=\"TableTextClass\"/>\r\n        <uitable:template>\r\n            <Input id=\"id_condtotalsumm\"\r\n                value=\"{path:'LNSumm>Wrbtr', formatter:'AssbcAssignBarcode.model.formatter.fnAmount'}\"\r\n                editable=\"false\"\r\n                change=\"fnCustomvalchange\"\r\n                class=\"suminput\"/>\r\n        </uitable:template>\r\n    </uitable:Column>\r\n\r\n    <!-- Column: Invoice Amount -->\r\n    <uitable:Column>\r\n        <Label text=\"Invoice Amount\" class=\"TableTextClass\"/>\r\n        <uitable:template>\r\n            <Input id=\"id_InvAmtsumm\"\r\n                editable=\"true\"\r\n                change=\"fnInvSummChange\"\r\n                type=\"Number\"\r\n                class=\"suminput\"\r\n                value=\"{path:'LNSumm>InvoiceAmt', formatter:'AssbcAssignBarcode.model.formatter.fnAmount'}\"/>\r\n        </uitable:template>\r\n    </uitable:Column>\r\n\r\n    <!-- Column: Deviation -->\r\n    <uitable:Column>\r\n        <Label text=\"Deviation\" class=\"TableTextClass\"/>\r\n        <uitable:template>\r\n            <Input id=\"id_differencesumm\"\r\n                editable=\"false\"\r\n                change=\"fnDifferenceChange\"\r\n                type=\"Number\"\r\n                class=\"suminput\"\r\n                value=\"{path:'LNSumm>Difference', formatter:'AssbcAssignBarcode.model.formatter.fn_indicator'}\"/>\r\n        </uitable:template>\r\n    </uitable:Column>\r\n\r\n</uitable:Table>\r\n</VBox>\r\n    <!--  <Table id=\"id_Sel_Table\" items=\"{LNSumm>/}\" mode=\"None\" class=\"MTableClass\" noDataText=\"Loading...\">-->\r\n    <!--    <columns >-->\r\n    <!--      <Column  hAlign=\"Center\">-->\r\n    <!--        <Text text=\"Condition\" class=\"TableTextClass\"/>-->\r\n    <!--      </Column>-->\r\n    <!--      <Column  hAlign=\"Center\">-->\r\n    <!--        <Text text=\"Liability\" class=\"TableTextClass\"/>-->\r\n    <!--      </Column>-->\r\n    <!--      <Column  hAlign=\"Center\">-->\r\n    <!--        <Text text=\"Invoice Amount\" class=\"TableTextClass\"/>-->\r\n    <!--      </Column>-->\r\n    <!--      <Column  hAlign=\"Center\">-->\r\n    <!--        <Text text=\"Deviation\" class=\"TableTextClass\"/>-->\r\n    <!--      </Column>-->\r\n    <!--    </columns>-->\r\n    <!--  <items>-->\r\n    <!--      <ColumnListItem>-->\r\n    <!--        <cells>-->\r\n              <!-- Condition Text -->\r\n    <!--          <Text text=\"{LNSumm>Kschl}-{LNSumm>Vtext}\"/>-->\r\n              <!-- Amount change=\"fnAmountChange\"-->\r\n    <!--          <Input id=\"id_condtotalsumm\"  value=\"{path:'LNSumm>Wrbtr',formatter:'AssbcAssignBarcode.model.formatter.fnAmount'}\"-->\r\n    <!--             editable = \"false\" change =\"fnCustomvalchange\"/>-->\r\n              <!-- Invoice Amt -->\r\n    <!--          <Input id=\"id_InvAmtsumm\" editable=\"true\" change=\"fnInvSummChange\" type=\"Number\"-->\r\n    <!--                     value=\"{path:'LNSumm>InvoiceAmt',formatter:'AssbcAssignBarcode.model.formatter.fnAmount'}\"/>-->\r\n              <!-- Diff -->\r\n    <!--          <Input id=\"id_differencesumm\" editable=\"false\" change=\"fnDifferenceChange\" type=\"Number\"-->\r\n    <!--              value=\"{path:'LNSumm>Difference',formatter:'AssbcAssignBarcode.model.formatter.fn_indicator'}\"/>-->\r\n    <!--        </cells>-->\r\n    <!--      </ColumnListItem>-->\r\n    <!--    </items>-->\r\n    <!--</Table>-->\r\n    </content>\r\n    <beginButton>\r\n      <Button text=\"{i18n>Close}\" tooltip=\"{i18n>Close}\"  icon=\"Images/cancel.svg\" class=\"gl_canbtn simcan \" press=\"fnCancelSumm\" />\r\n    </beginButton>\r\n    <endButton>\r\n      <Button text=\"Submit\" class=\"  gl_subbtn simpost \"  icon=\"Images/subsumab.svg\"  press=\"fnSubmitSumm\" />\r\n    </endButton>\r\n  </Dialog>\r\n</core:FragmentDefinition>",
