		"FSC360NEW/fragment/HSNCode_PO.fragment.xml": "<core:FragmentDefinition xmlns=\"sap.m\" xmlns:core=\"sap.ui.core\">\r\n\t<SelectDialog title=\"{i18n>Select HSN Code}\"  items=\"{JSHSN>/}\" liveChange=\"fn_HSN_LC\" class=\"cl_frag\" \r\n\t\tconfirm=\"fn_Confirm_HSN_PO\" >\r\n\t\t<!--<StandardListItem  title=\"{JSHSN>Steuc}\" description=\"{JSHSN>Text1}\"/>-->\r\n\t\t\t<StandardListItem \r\n    title=\"{= ${JSHSN>Steuc} + ' - ' + ${JSHSN>Text1} }\" \r\n/>\r\n\t</SelectDialog>\r\n</core:FragmentDefinition>",
