		"FSC360NEW/fragment/Confirmation.fragment.xml": "<core:FragmentDefinition xmlns=\"sap.m\" xmlns:ui=\"sap.ui.table\" xmlns:core=\"sap.ui.core\">\r\n\t<Dialog title=\"{i18n>Analysis}\" showHeader=\"true\" class=\"sapUiSizeCompact cl_frag\" resizable=\"true\"\r\n\t\tdraggable=\"true\">\r\n\t\t<content>\r\n\t\t\t<List items=\"{JMCONSucc>/}\" id=\"id_consuccMSG\" class=\"sapUiTinyMarginTop sapUiSizeCompact\">\r\n\t\t\t\t<items>\r\n\t\t\t\t\t<CustomListItem type=\"Active\" class=\"APW_MasterListClass\">\r\n\t\t\t\t\t\t<Toolbar class=\"cl_toolBar\">\r\n\t\t\t\t\t\t\t<Text text=\"{JMCONSucc>Message}\" wrapping=\"false\" class=\"sapUiSmallMarginBegin APW_SuccessMsgTxt\"/>\r\n\t\t\t\t\t\t\t<ToolbarSpacer></ToolbarSpacer>\r\n\t\t\t\t\t\t</Toolbar>\r\n\t\t\t\t\t</CustomListItem>\r\n\t\t\t\t</items>\r\n\t\t\t</List>\r\n\t\t\t<List items=\"{JMCONError>/}\" id=\"id_conerrMSG\" class=\"sapUiTinyMarginTop sapUiSizeCompact\">\r\n\t\t\t\t<items>\r\n\t\t\t\t\t<CustomListItem type=\"Active\" class=\" APW_MasterListClass\">\r\n\t\t\t\t\t\t<Toolbar class=\"cl_toolBar\">\r\n\t\t\t\t\t\t\t<Text text=\"{JMCONError>Message}\" wrapping=\"false\" class=\"sapUiSmallMarginBegin APW_ErrorMsgTxt\"/>\r\n\t\t\t\t\t\t\t<ToolbarSpacer></ToolbarSpacer>\r\n\t\t\t\t\t\t</Toolbar>\r\n\t\t\t\t\t</CustomListItem>\r\n\t\t\t\t</items>\r\n\t\t\t</List>\r\n\t\t</content>\r\n\t\t<endButton>\r\n\t\t\t<Button text=\"{i18n>Close}\" class=\"APW_CloseErrorBtn\" press=\"fn_Confirmation_frag_close\" tooltip=\"{i18n>Close}\"/>\r\n\t\t</endButton>\r\n\t\t<!--<HBox class=\"sapUiSizeCompact sapUiSmallMargin\" alignContent=\"Cneter\" alignItems=\"Center\" justifyContent=\"Center\">-->\r\n\t\t<!--\t<Button text=\"{i18n>Cancel}\" press=\"fn_Confirmation_frag_close\" class=\"sapUiTinyMarginEnd cl_fragcancelbtn\" tooltip=\"{i18n>Cancel}\"/>-->\r\n\t\t<!--</HBox>-->\r\n\t</Dialog>\r\n</core:FragmentDefinition>",
