		"FSC360NEW/fragment/CustomCol_Autopark.fragment.xml": "<core:FragmentDefinition xmlns=\"sap.m\" xmlns:core=\"sap.ui.core\">\r\n  <Popover title=\"Customize Columns\" placement=\"Bottom\" class=\"sapUiContentPadding clcustomizepop\">\r\n    <VBox class=\"customcol_padding\">\r\n      <Label text=\"Choose Template\" class=\"popup_subheading\"/>\r\n      <HBox  class=\"templateSelectWrapper\"  alignItems=\"Center\" >\r\n        <Input  value=\"{viewModel>/selectedTemplate}\" \r\n        placeholder=\"Select Template\" showValueHelp=\"false\" class=\"templateInputDropdown\"/>\r\n        <Button icon=\"Images/chevron-down.svg\" press=\"fn_onOpenTemplatePopover\" class=\"templateDropdownArrow\"/>\r\n      </HBox>\r\n  <HBox alignItems=\"Center\" class=\" customCheckWrapper sapUiTinyMarginBegin sapUiTinyMarginBottom\">\r\n        <CheckBox \r\n                  text=\"Select All\"\r\n                  select=\"fn_onSelectAll\" />\r\n                   <Text text=\"Select All\"  class=\"sapUiTinyMarginEnd  popuptext\" />\r\n      </HBox>\r\n\r\n<List\r\n  id=\"idFieldListfullfill\"\r\n  items=\"{\r\n    path: 'FilterTableModel>/',\r\n    templateShareable: false\r\n  }\"\r\n  showSeparators=\"None\"\r\n  mode=\"None\">\r\n  \r\n  <CustomListItem type=\"Inactive\" class=\"cl_dragItem\">\r\n    <HBox alignItems=\"Center\" class=\"clListItemStyled customCheckWrapper\"\r\n          draggable=\"true\"\r\n          dragstart=\"onDragStart\"\r\n          dragover=\"onDragOver\"\r\n          drop=\"onDrop\">\r\n      \r\n      <!-- Drag handle -->\r\n      <Image src=\"Images/dots-drag.svg\" class=\"dots-drag\"/>\r\n\r\n      <!-- Checkbox -->\r\n      <CheckBox\r\n        selected=\"{FilterTableModel>visible}\"\r\n        width=\"100%\"/>\r\n      \r\n      <!-- Label -->\r\n      <Text text=\"{FilterTableModel>label}\" class=\"sapUiTinyMarginEnd popuptext\"/>\r\n      \r\n    </HBox>\r\n  </CustomListItem>\r\n</List>\r\n      <!--<HBox justifyContent=\"SpaceBetween\" class=\"sapUiSmallMarginTop\">-->\r\n      \r\n      <!--  <Button text=\"Apply\" type=\"Emphasized\" press=\"fn_onApplyTemplate\" />-->\r\n      <!--</HBox>-->\r\n    </VBox>\r\n    <!-- <footer>-->\r\n    <!--  <Bar design=\"Footer\" class=\"grey_background\">-->\r\n    <!--    <contentRight>-->\r\n    <!--      <Button text=\"Apply\"-->\r\n    <!--              type=\"Emphasized\"-->\r\n    <!--              class=\"bluebtn bluebtnfragment\"-->\r\n    <!--              press=\"fn_onApplyTemplate\" />-->\r\n    <!--    </contentRight>-->\r\n    <!--  </Bar>-->\r\n    <!--</footer>-->\r\n  </Popover>\r\n</core:FragmentDefinition>",
