		"FSC360NEW/fragment/ErrorrPayAppr.fragment.xml": "<core:FragmentDefinition xmlns=\"sap.m\" xmlns:core=\"sap.ui.core\">\r\n\t<Dialog id=\"errorDialog\" showHeader=\"false\" class=\"cl_successDialog cl_rejpopup\" stretchOnPhone=\"true\" draggable=\"false\" resizable=\"false\">\r\n\t\t<VBox class=\"cl_invublsuccess\"  width=\"100%\" alignItems=\"Center\" justifyContent=\"Start\">\r\n\t\t\t<VBox class=\"cl_warningTopCurve1\" alignItems=\"Center\" justifyContent=\"Center\">\r\n\t\t\t\t<Image src=\"Images/errorinv.svg\" class=\"cl_successIcon\"/>\r\n\t\t\t</VBox>\r\n\t\t\t<VBox class=\"cl_errorContent1\" alignItems=\"Center\" justifyContent=\"Center\">\r\n\t\t\t\t<Text text=\"\" id=\"id_error_text\" class=\"cl_successTitle\"/>\r\n\t\t\t\t\r\n\t\t\t</VBox>\r\n\t\t\t<HBox class=\"cl_errorFooter\"  width=\"100%\" alignItems=\"Center\" justifyContent=\"Center\">\r\n\t\t\t\t<Button text=\"Ō£Ģ Close\" class=\"cl_btn_searchapp cl_btn_searchsuccess\" press=\"fn_onCloseErrorDialog\"/>\r\n\t\t\t</HBox>\r\n\t\t</VBox>\r\n\t</Dialog>\r\n</core:FragmentDefinition>",
