		"FSC360NEW/fragment/Reject.fragment.xml": "<core:FragmentDefinition xmlns=\"sap.m\" xmlns:core=\"sap.ui.core\">\r\n\t<Dialog title=\"{i18n>Reject}\" class=\"APW_DilogClass\">\r\n\t\t<content>\r\n\t\t\t<VBox id=\"id_revreasonBox\" visible=\"false\">\r\n\t\t\t\t<Label text=\"{i18n>Reason for reversal}\" class=\"FSC_Label cl_revreason_lab sapUiTinyMarginBegin sapUiTinyMarginTop\"\r\n\t\t\t\t\ttooltip=\"{i18n>Reason for reversal}\"></Label>\r\n\t\t\t\t<Select items=\"{JSRevReasons>/}\" id=\"id_SelReversal\" width=\"20rem\" change=\"\" selectedKey=\"1\"\r\n\t\t\t\t\tclass=\"cl_swRevReasonSelect cl_trastype sapUiSizeCompact sapUiTinyMarginBegin\">\r\n\t\t\t\t\t<core:Item key=\"{JSRevReasons>Stgrd}\" text=\"{JSRevReasons>Txt40}\"/>\r\n\t\t\t\t</Select>\r\n\t\t\t</VBox>\r\n\t\t\t<Text text=\"{i18n>Comments}\" class=\"sapUiTinyMarginBegin sapUiTinyMarginTop FSC_Label\"></Text>\r\n\t\t\t<TextArea id=\"id_Remark_Rejct\" class=\"sapUiTinyMarginBegin textArea\" liveChange=\"fnLiveRemark\" width=\"95%\"/>\r\n\t\t\t<!--<OverflowToolbar class=\"barClass sapUiTinyMarginTop\">-->\r\n\t\t\t<!--\t<Button type=\"Reject\" text=\"{i18n>cancel}\" icon=\"sap-icon://decline\" press=\"fnCloseReject\" tooltip=\"{i18n>cancel}\" class=\"sapUiSizeCompact\"/>-->\r\n\t\t\t<!--\t<ToolbarSpacer/>-->\r\n\t\t\t<!--\t<Button type=\"Accept\" icon=\"sap-icon://accept\" text=\"{i18n>Submit}\" press=\"fnRejectRemark\" tooltip=\"{i18n>Submit}\" class=\"sapUiSizeCompact\"/>-->\r\n\t\t\t<!--</OverflowToolbar>-->\r\n\t\t</content>\r\n\t\t<HBox class=\"sapUiSizeCompact sapUiSmallMargin\" alignContent=\"Cneter\" alignItems=\"Center\" justifyContent=\"Center\">\r\n\t\t\t<Button type=\"Reject\" text=\"{i18n>Cancel}\" press=\"fnCloseReject\" tooltip=\"{i18n>cancel}\"\r\n\t\t\t\tclass=\"sapUiTinyMarginEnd cl_fragcancelbtn sapUiSizeCompact\"/>\r\n\t\t\t<Button type=\"Accept\" tooltip=\"{i18n>Submit for Reject the Queue ID}\" press=\"fnRejectRemark\" text=\"{i18n>Submit}\"\r\n\t\t\t\tclass=\"sapUiTinyMarginBegin cl_fragfinalbtn sapUiSizeCompact\"/>\r\n\t\t</HBox>\r\n\t</Dialog>\r\n</core:FragmentDefinition>",
