		"FSC360NEW/fragment/SuccessReuse.fragment.xml": "<core:FragmentDefinition xmlns=\"sap.m\" xmlns:core=\"sap.ui.core\" xmlns:mvc=\"sap.ui.core.mvc\">\r\n\t<Dialog id=\"successDialog\" showHeader=\"false\" class=\"cl_successDialog\" stretchOnPhone=\"true\" draggable=\"false\" resizable=\"false\">\r\n\t\t<VBox class=\"cl_invublsuccess\" width=\"100%\" alignItems=\"Center\" justifyContent=\"Start\">\r\n\t\t\t\r\n\t\t\t<!-- Top Section with Success Icon -->\r\n\t\t\t<VBox class=\"cl_successTopCurve\" alignItems=\"Center\" justifyContent=\"Center\">\r\n\t\t\t\t<Image src=\"Images/rocket.svg\" class=\"cl_successIcon\"/>\r\n\t\t\t</VBox>\r\n\r\n\t\t\t<!-- Dynamic Message -->\r\n\t\t\t<VBox class=\"cl_successContent\" alignItems=\"Center\" justifyContent=\"Center\">\r\n\t\t\t\t<Text text=\"{successModel>/message}\" class=\"cl_successTitle_medium\" id=\"id_dynamictest\"/>\r\n\t\t\t</VBox>\r\n\r\n\t\t\t<!-- Footer with Close Button -->\r\n\t\t\t<HBox class=\"cl_errorFooter\" width=\"100%\" alignItems=\"Center\" justifyContent=\"Center\">\r\n\t\t\t\t<Button text=\"Ō£Ģ Close \" type=\"Emphasized\" class=\"cl_btn_searchapp cl_btn_searchsuccess\" press=\"fn_closeSuccess\"/>\r\n\t\t\t</HBox>\r\n\t\t</VBox>\r\n\t</Dialog>\r\n</core:FragmentDefinition>",
		"FSC360NEW/fragment/Error.fragment.xml": "<core:FragmentDefinition xmlns=\"sap.m\" xmlns:ui=\"sap.ui.table\" xmlns:core=\"sap.ui.core\">\r\n\t<Dialog title=\"{i18n>ErrorAnalysis}\" showHeader=\"true\"  class=\"sapUiSizeCompact cl_frag cl_error_dialog\" contentWidth=\"40%\"\r\n\t\tcontentHeight=\"30%\" resizable=\"true\" draggable=\"true\">\r\n\t\t<content>\r\n\t\t\t<List items=\"{JMError>/}\" class=\"sapUiMediumMarginTop sapUiSizeCompact\" updateFinished=\"fnNavDetail\">\r\n\t\t\t\t<items>\r\n\t\t\t\t\t<CustomListItem type=\"Active\" press=\"onListItemPress\" class=\"sapUiSmallMarginTop APW_MasterListClass\">\r\n\t\t\t\t\t\t<Toolbar class=\"cl_toolBar\">\r\n\t\t\t\t\t\t\t<Text text=\"{JMError>Message}\" wrapping=\"false\" class=\"sapUiSmallMarginBegin APW_ErrorMsgTxt\"/>\r\n\t\t\t\t\t\t\t<ToolbarSpacer></ToolbarSpacer>\r\n\t\t\t\t\t\t</Toolbar>\r\n\t\t\t\t\t</CustomListItem>\r\n\t\t\t\t</items>\r\n\t\t\t</List>\r\n\t\t</content>\r\n\t\t<endButton>\r\n\t\t\t<Button text=\"{i18n>Close}\" class=\"APW_CloseErrorBtn\" press=\"fn_Error_frag_close\" tooltip=\"{i18n>Close}\"/>\r\n\t\t</endButton>\r\n\t</Dialog>\r\n</core:FragmentDefinition>",
