		"FSC360NEW/fragment/WarningReuse.fragment.xml": "<core:FragmentDefinition xmlns=\"sap.m\" xmlns:core=\"sap.ui.core\" xmlns:mvc=\"sap.ui.core.mvc\">\r\n\t<Dialog id=\"warningDialog\" showHeader=\"false\" class=\"cl_successDialog\" stretchOnPhone=\"true\" draggable=\"false\" resizable=\"false\">\r\n\t\t<VBox class=\"cl_invublwarn\" width=\"100%\" alignItems=\"Center\" justifyContent=\"Start\">\r\n\t\t\t\r\n\t\t\t<!-- Top Section with Success Icon -->\r\n\t\t\t<VBox class=\"cl_warnTopCurve\" alignItems=\"Center\" justifyContent=\"Center\">\r\n\t\t\t\t<Image src=\"Images/warning.svg\" class=\"cl_successIcon\"/>\r\n\t\t\t</VBox>\r\n\r\n\t\t\t<!-- Dynamic Message -->\r\n\t\t\t<VBox class=\"cl_successContent\" alignItems=\"Center\" justifyContent=\"Center\">\r\n\t\t\t\t<Text text=\"{warnModel>/message}\" class=\"cl_successTitle_medium\" id=\"id_dynamicwarntest\"/>\r\n\t\t\t</VBox>\r\n\r\n\t\t\t<!-- Footer with Close Button -->\r\n\t\t\t<HBox class=\"cl_errorFooter\" width=\"100%\" alignItems=\"Center\" justifyContent=\"Center\">\r\n\t\t\t\t<Button text=\"Ō£Ģ Close \" type=\"Emphasized\" class=\"cl_btn_searchapp cl_btn_searchsuccess\" press=\"fn_closewarn\"/>\r\n\t\t\t</HBox>\r\n\t\t</VBox>\r\n\t</Dialog>\r\n</core:FragmentDefinition>",
