		"FSC360NEW/fragment/TemplatePopover_apk.fragment.xml": "<core:FragmentDefinition xmlns=\"sap.m\" xmlns:core=\"sap.ui.core\">\r\n  <Popover showHeader=\"false\" placement=\"Bottom\" id=\"idTemplatePopover_fulfill\" class=\"clcustomizetemppop\">\r\n    <VBox>\r\n    \r\n      <!--\t<List id=\"idTemplateListfulfill\" items=\"{viewModel1>/templates}\" -->\r\n      <!--itemPress=\"fn_onTemplateListItemPress\" mode=\"SingleSelectMaster\" selectionChange=\"fn_onTemplateSelectionChange\">-->\r\n      <!--  <CustomListItem>-->\r\n      <!--    <HBox justifyContent=\"SpaceBetween\" width=\"100%\" class=\"templateListItemBox\">-->\r\n      <!--      <Text text=\"{viewModel1>name}\" />-->\r\n      <!--      <Button icon=\"Images/trash-can-outline.svg\" press=\"fn_onDeleteTemplate\" type=\"Transparent\"/>-->\r\n      <!--    </HBox>-->\r\n      <!--  </CustomListItem>-->\r\n      <!--</List>-->\r\n        <List  items=\"{viewModel1>/templates}\" \r\n      itemPress=\"fn_onTemplateListItemPress\" mode=\"SingleSelectMaster\">\r\n  <CustomListItem type=\"Active\">\r\n    <HBox justifyContent=\"SpaceBetween\" width=\"100%\" class=\"templateListItemBox\">\r\n      <Text text=\"{viewModel1>name}\" />\r\n      <!-- Pass current binding context to delete -->\r\n      <Button icon=\"Images/trash-can-outline.svg\"\r\n              press=\"fn_onDeleteTemplateRow\"\r\n              type=\"Transparent\"/>\r\n    </HBox>\r\n  </CustomListItem>\r\n</List>\r\n   \r\n   <HBox justifyContent=\"SpaceBetween\" width=\"100%\" class=\"templateListItemBox\">\r\n            <Text text=\"Create Template\" />\r\n            <Button icon=\"Images/plu_fragment.svg\" press=\"fn_onOpenCreateTemplateDialog\" type=\"Transparent\"/>\r\n          </HBox>\r\n    </VBox>\r\n  </Popover>\r\n</core:FragmentDefinition>",
		"FSC360NEW/fragment/AddAttachment.fragment.xml": "<core:FragmentDefinition xmlns=\"sap.m\" xmlns:core=\"sap.ui.core\">\r\n\t<Dialog title=\"{i18n>AddAttachment}\" class=\"sapUiContentPadding cl_addattach cl_pop\">\r\n\t\t<content height=\"100%\">\r\n\t\t\t\r\n\t\t\t<List items=\"{JSImgList>/}\">\r\n\t\t\t\t<StandardListItem\r\n\t\t\t\t\ttitle=\"{JSImgList>Name}\"\r\n\t\t\t\t\ttype=\"Active\"\r\n\t\t\t\t\tpress=\"fn_View_Attachment\"\r\n\t\t\t\t\ticon=\"sap-icon://attachment\"\r\n\t\t\t\t\tclass=\"cl_fnt_size cl_color_head sapUiSizeCompact cl_font\" />\r\n\t\t\t</List>\r\n\r\n\t\t\t<UploadCollection\r\n\t\t\t\tid=\"id_UploadCollection\"\r\n\t\t\t\tmultiple=\"false\"\r\n\t\t\t\tsameFilenameAllowed=\"false\"\r\n\t\t\t\tinstantUpload=\"false\" \r\n\t\t\t\tshowSeparators=\"All\"\r\n\t\t\t\tchange=\"onFileUploadChange\" \r\n\t\t\t\tfileDeleted=\"onFileDeleted\"\r\n\t\t\t\tfilenameLengthExceed=\"onFilenameLengthExceed\"\r\n\t\t\t\tfileSizeExceed=\"onFileSizeExceed\"\r\n\t\t\t\ttypeMissmatch=\"onTypeMissmatch\"\r\n\t\t\t\tnoDataText=\" \"\r\n\t\t\t\tmode=\"Delete\" />\r\n\r\n\t\t\t<HBox class=\"sapUiSizeCompact sapUiSmallMargin\" alignItems=\"End\" justifyContent=\"Center\">\r\n\t\t\t\t<Button text=\"Cancel\" tooltip=\"Cancel\" press=\"fn_cancel_add_attachment\" class=\"sapUiTinyMarginEnd cl_fragcancelbtn\" />\r\n\t\t\t\t<Button text=\"Upload\" tooltip=\"Upload the Attachments with Queue ID\" press=\"fn_ok_add_attachment\" class=\"sapUiTinyMarginBegin cl_fragfinalbtn\" />\r\n\t\t\t</HBox>\r\n\r\n\t\t</content>\r\n\t</Dialog>\r\n</core:FragmentDefinition>",
		"FSC360NEW/fragment/Recallerror.fragment.xml": "<core:FragmentDefinition xmlns=\"sap.m\" xmlns:core=\"sap.ui.core\">\r\n    <Dialog id=\"errorDialog\"\r\n            showHeader=\"false\"\r\n            class=\"cl_successDialog\"\r\n            stretchOnPhone=\"true\"\r\n            draggable=\"false\"\r\n            resizable=\"false\">\r\n        \r\n        <VBox class=\"cl_successWrapper\" alignItems=\"Center\" justifyContent=\"Start\">\r\n            <VBox class=\"cl_errorTopCurve\" alignItems=\"Center\" justifyContent=\"Center\">\r\n                <Image src=\"Images/error.svg\" class=\"cl_successIcon\" />\r\n            </VBox>\r\n            \r\n            <VBox class=\"cl_errorContent\" alignItems=\"Center\" justifyContent=\"Center\">\r\n                <Text text=\"Recall Failed\" class=\"cl_successTitle\" />\r\n                <Text text=\"{errorModel>/message}\" class=\"cl_successMessage\" />\r\n           <!--<Button text=\"Ō£Ģ Close\" type=\"Reject\"-->\r\n           <!--             class=\"cl_btn_searchapp cl_btn_searchsuccess\"-->\r\n           <!--             press=\".onCloseErrorDialog\" />-->\r\n            </VBox>\r\n                 <HBox class=\"cl_errorFooter\" alignItems=\"Center\" justifyContent=\"Center\">\r\n            <Button text=\"Ō£Ģ Close\"\r\n                    \r\n                    class=\"cl_btn_searchapp cl_btn_searchsuccess\"\r\n                    press=\"onCloseErrorDialog\" />\r\n        </HBox>   \r\n        </VBox>\r\n   \r\n       \r\n    </Dialog>\r\n</core:FragmentDefinition>",
