		"FSC360NEW/fragment/CommentsNponRej.fragment.xml": "<core:FragmentDefinition\r\n  xmlns=\"sap.m\"\r\n  xmlns:core=\"sap.ui.core\"\r\n  >\r\n\r\n  <Dialog\r\n    id=\"id_nonpocommentrej\"\r\n    title=\"Workflow Comments\"\r\n    icon=\"sap-icon://message\"\r\n    type=\"Message\"\r\n    class=\"cl_agentDialog\"\r\n    afterClose=\".onRemarkDialogClose\">\r\n\r\n \t<Text text=\"{i18n>Remarks}\" class=\"cl_dialogLabelnpon\"></Text>\r\n      <TextArea\r\n        id=\"id_rejComments\"\r\n        placeholder=\"Enter here...\"\r\n        maxLength=\"255\"\r\n        width=\"98%\"\r\n        rows=\"3\"\r\n        class=\"cl_remarksInput customTextArea\"\r\n        liveChange=\"fnLiveRemark\" />\r\n      \r\n    \r\n      <beginButton>\r\n            <Button\r\n                text=\"Cancel\"    id=\"id_rejectrej\" icon=\"Images/cancel.svg\"\r\n                 press=\"fn_rejcancel\"  class=\"gl_canbtn gl_canbtn1\" />\r\n        </beginButton>\r\n\r\n        <endButton>\r\n            <Button\r\n                text=\"Submit\"  id=\"id_approverej\" icon=\"Images/approve_image.svg\"\r\n               press=\"fn_rejsubmit\" class=\" gl_subbtn gl_subbtn1 \" />\r\n        </endButton>\r\n  </Dialog>\r\n</core:FragmentDefinition>",
